/* eslint-disable no-var */
/* eslint-disable vars-on-top */
/* eslint-disable no-undef */
/**
 * AMW Django ERP - Global HTMX Event Delegation
 *
 * This script registers global listeners on document.body to handle:
 * - Toast notifications from HX-Trigger headers
 * - Modal open/close/reopen cycles
 * - Sidebar scroll persistence
 * - Topbar dropdown dismissal
 *
 * All listeners use event delegation so they survive HTMX DOM swaps.
 * No logic depends on DOMContentLoaded; listeners are active immediately.
 */

// ──────────────────────────────────────────────
// Sidebar Scroll Persistence
// ──────────────────────────────────────────────
document.body.addEventListener("htmx:afterSettle", function () {
    var sidebar = document.querySelector(".sidebar");
    if (sidebar) {
        var saved = sessionStorage.getItem("sidebar-scroll");
        if (saved) {
            sidebar.scrollTop = parseInt(saved, 10);
        }
        // Attach scroll listener once (guard against duplicates)
        if (!sidebar._scrollListenerAttached) {
            sidebar.addEventListener("scroll", function () {
                sessionStorage.setItem("sidebar-scroll", sidebar.scrollTop);
            });
            sidebar._scrollListenerAttached = true;
        }
    }
});

// ──────────────────────────────────────────────
// Topbar Dropdown Dismissal (Outside Click)
// ──────────────────────────────────────────────
document.body.addEventListener("click", function (e) {
    var dropdowns = document.querySelectorAll(".topbar__dropdown");
    var buttons = document.querySelectorAll(".topbar__profile-btn");
    dropdowns.forEach(function (dropdown, i) {
        if (
            !dropdown.contains(e.target) &&
            buttons[i] &&
            !buttons[i].contains(e.target)
        ) {
            dropdown.classList.remove("topbar__dropdown--open");
        }
    });
});

// ──────────────────────────────────────────────
// Toast Notification System
// ──────────────────────────────────────────────

/**
 * Show a toast notification.
 * Triggered via HTMX HX-Trigger header or manual JS call.
 */
window.showToast = function (event) {
    var container = document.getElementById("toast-container");
    if (!container) {
        return;
    }
    var data = event.detail && event.detail.value ? event.detail.value : event;
    var message = data.message || data;
    var type = data.type || "info";
    var duration = data.duration || 4000;

    var toast = document.createElement("div");
    toast.className = "toast toast--" + type;
    toast.setAttribute("role", "alert");
    toast.innerHTML = "<span>" + message + "</span>";

    container.appendChild(toast);

    setTimeout(function () {
        toast.style.animation = "toast-out 0.3s ease forwards";
        setTimeout(function () {
            if (toast.parentNode) {
                toast.parentNode.removeChild(toast);
            }
        }, 300);
    }, duration);
};

/**
 * Render toast from HX-Trigger header on successful HTMX responses.
 */
document.body.addEventListener("htmx:afterOnLoad", function (event) {
    renderToastFromHeader(event.detail.xhr);
});

/**
 * Render toast from HX-Trigger header on HTMX error responses.
 */
document.body.addEventListener("htmx:responseError", function (event) {
    renderToastFromHeader(event.detail.xhr);
});

/**
 * Parse HX-Trigger header and show toast if present.
 */
function renderToastFromHeader(xhr) {
    if (!xhr) {
        return;
    }
    var triggerHeader = xhr.getResponseHeader("HX-Trigger");
    if (!triggerHeader) {
        return;
    }
    try {
        var triggers = JSON.parse(triggerHeader);
        if (triggers.showToast) {
            var data = triggers.showToast;
            var container = document.getElementById("toast-container");
            if (!container) {
                return;
            }
            var message = data.message || "";
            var type = data.type || "info";
            var duration = data.duration || 4000;

            var toast = document.createElement("div");
            toast.className = "toast toast--" + type;
            toast.setAttribute("role", "alert");
            toast.innerHTML = "<span>" + message + "</span>";
            container.appendChild(toast);

            setTimeout(function () {
                toast.style.animation = "toast-out 0.3s ease forwards";
                setTimeout(function () {
                    if (toast.parentNode) {
                        toast.parentNode.removeChild(toast);
                    }
                }, 300);
            }, duration);
        }

        // Handle ledger refresh trigger
        if (triggers.refreshLedger) {
            refreshLedgerTable();
        }

        // Update stock values
        if (triggers.newStock) {
            var stockEl = document.getElementById("current-stock");
            if (stockEl) {
                stockEl.textContent = triggers.newStock;
            }
        }
        if (triggers.newValue) {
            var valueEl = document.getElementById("stock-value");
            if (valueEl) {
                valueEl.textContent = triggers.newValue;
            }
        }
    } catch (e) {
        // Ignore parse errors (e.g., malformed JSON in header)
    }
}

/**
 * Refresh the ledger table after stock adjustment.
 */
function refreshLedgerTable() {
    var template = document.getElementById("ledger-template");
    if (template) {
        var tbody = document.getElementById("ledger-body");
        if (tbody) {
            tbody.innerHTML = template.content ? template.content.innerHTML : template.innerHTML;
        }
    }
}

// ──────────────────────────────────────────────
// Modal Lifecycle (Open / Close / Reopen)
// ──────────────────────────────────────────────

/**
 * Open a modal by ID.
 * The ID should point to the .modal-overlay element.
 * Sets display:flex and adds active class for animation.
 */
window.openModal = function (modalId) {
    var overlay = document.getElementById(modalId);
    if (overlay) {
        overlay.style.display = "flex";
        overlay.classList.add("modal--open");
        // Prevent body scroll when modal is open
        document.body.style.overflow = "hidden";
    }
};

/**
 * Close a modal by ID.
 * Sets display:none and removes active class.
 */
window.closeModal = function (modalId) {
    var overlay = document.getElementById(modalId);
    if (overlay) {
        overlay.style.display = "none";
        overlay.classList.remove("modal--open");
        // Restore body scroll
        document.body.style.overflow = "";
    }
};

/**
 * Global click handler for modal close buttons and overlays.
 * Uses event delegation to handle clicks anywhere in the document.
 */
document.body.addEventListener("click", function (e) {
    // Close button (data-modal-close or .modal__close)
    var closeBtn = e.target.closest("[data-modal-close], .modal__close");
    if (closeBtn) {
        var modalId = closeBtn.getAttribute("data-modal-close");
        if (modalId) {
            closeModal(modalId);
        } else {
            // Find parent modal overlay
            var overlay = e.target.closest(".modal-overlay");
            if (overlay) {
                overlay.style.display = "none";
                overlay.classList.remove("modal--open");
                document.body.style.overflow = "";
            }
        }
        return;
    }

    // Overlay click (clicking outside modal content)
    if (e.target.classList.contains("modal-overlay")) {
        e.target.style.display = "none";
        e.target.classList.remove("modal--open");
        document.body.style.overflow = "";
    }
});

/**
 * Global keydown handler for Escape key to close modals.
 */
document.body.addEventListener("keydown", function (e) {
    if (e.key === "Escape") {
        var openModal = document.querySelector(".modal-overlay.modal--open");
        if (!openModal) {
            openModal = document.querySelector(".modal-overlay[style*='display: flex']");
        }
        if (openModal) {
            openModal.style.display = "none";
            openModal.classList.remove("modal--open");
            document.body.style.overflow = "";
        }
    }
});

/**
 * Close modal on HTMX after swap (cleanup for any lingering state).
 */
document.body.addEventListener("htmx:afterSwap", function () {
    // Ensure no orphaned modal overlays remain after HTMX swaps
    var overlays = document.querySelectorAll(".modal-overlay");
    overlays.forEach(function (overlay) {
        if (overlay.style.display === "flex" && !overlay.querySelector(".modal__content")) {
            overlay.style.display = "none";
            overlay.classList.remove("modal--open");
            document.body.style.overflow = "";
        }
    });
});
